#include "biblia.h"

void Biblia::CarregarTito(Biblia* b) {
    b->dados[TITO].nome = wxT("Tito");

    b->dados[TITO].capitulos[1].versos[1] = wxT("Paulo, servo de Deus, e apóstolo de Jesus Cristo, segundo a fé dos eleitos de Deus, e o pleno conhecimento da verdade que é segundo a piedade,");
    b->dados[TITO].capitulos[1].versos[2] = wxT("na esperança da vida eterna, a qual Deus, que não pode mentir, prometeu antes dos tempos eternos,");
    b->dados[TITO].capitulos[1].versos[3] = wxT("e no tempo próprio manifestou a sua palavra, mediante a pregação que me foi confiada segundo o mandamento de Deus, nosso Salvador;");
    b->dados[TITO].capitulos[1].versos[4] = wxT("a Tito, meu verdadeiro filho segundo a fé que nos é comum, graça e paz da parte de Deus Pai, e de Cristo Jesus, nosso Salvador.");
    b->dados[TITO].capitulos[1].versos[5] = wxT("Por esta causa te deixei em Creta, para que pusesses em boa ordem o que ainda não o está, e que em cada cidade estabelecesses anciãos, como já te mandei;");
    b->dados[TITO].capitulos[1].versos[6] = wxT("alguém que seja irrepreensível, marido de uma só mulher, tendo filhos crentes que não sejam acusados de dissolução, nem sejam desobedientes.");
    b->dados[TITO].capitulos[1].versos[7] = wxT("Pois é necessário que o bispo seja irrepreensível, como despenseiro de Deus, não soberbo, nem irascível, nem dado ao vinho, nem espancador, nem cobiçoso de torpe ganância;");
    b->dados[TITO].capitulos[1].versos[8] = wxT("mas hospitaleiro, amigo do bem, sóbrio, justo, piedoso, temperante;");
    b->dados[TITO].capitulos[1].versos[9] = wxT("retendo firme a palavra fiel, que é conforme a doutrina, para que seja poderoso, tanto para exortar na sã doutrina como para convencer os contradizentes.");
    b->dados[TITO].capitulos[1].versos[10] = wxT("Porque há muitos insubordinados, faladores vãos, e enganadores, especialmente os da circuncisão,");
    b->dados[TITO].capitulos[1].versos[11] = wxT("aos quais é preciso tapar a boca; porque transtornam casas inteiras ensinando o que não convém, por torpe ganância.");
    b->dados[TITO].capitulos[1].versos[12] = wxT("Um dentre eles, seu próprio profeta, disse: Os cretenses são sempre mentirosos, bestas ruins, glutões preguiçosos.");
    b->dados[TITO].capitulos[1].versos[13] = wxT("Este testemunho é verdadeiro. Portanto repreende-os severamente, para que sejam são na fé,");
    b->dados[TITO].capitulos[1].versos[14] = wxT("não dando ouvidos a fábulas judaicas, nem a mandamentos de homens que se desviam da verdade.");
    b->dados[TITO].capitulos[1].versos[15] = wxT("Tudo é puro para os que são puros, mas para os corrompidos e incrédulos nada é puro; antes tanto a sua mente como a sua consciência estão contaminadas.");
    b->dados[TITO].capitulos[1].versos[16] = wxT("Afirmam que conhecem a Deus, mas pelas suas obras o negam, sendo abomináveis, e desobedientes, e réprobos para toda boa obra.");

    b->dados[TITO].capitulos[2].versos[1] = wxT("Tu, porém, fala o que convém à sã doutrina.");
    b->dados[TITO].capitulos[2].versos[2] = wxT("Exorta os velhos a que sejam temperantes, sérios, sóbrios, sãos na fé, no amor, e na constância;");
    b->dados[TITO].capitulos[2].versos[3] = wxT("as mulheres idosas, semelhantemente, que sejam reverentes no seu viver, não caluniadoras, não dadas a muito vinho, mestras do bem,");
    b->dados[TITO].capitulos[2].versos[4] = wxT("para que ensinem as mulheres novas a amarem aos seus maridos e filhos,");
    b->dados[TITO].capitulos[2].versos[5] = wxT("a serem moderadas, castas, operosas donas de casa, bondosas, submissas a seus maridos, para que a palavra de Deus não seja blasfemada.");
    b->dados[TITO].capitulos[2].versos[6] = wxT("Exorta semelhantemente os moços a que sejam moderados.");
    b->dados[TITO].capitulos[2].versos[7] = wxT("Em tudo te dá por exemplo de boas obras; na doutrina mostra integridade, sobriedade,");
    b->dados[TITO].capitulos[2].versos[8] = wxT("linguagem sã e irrepreensível, para que o adversário se confunda, não tendo nenhum mal que dizer de nós.");
    b->dados[TITO].capitulos[2].versos[9] = wxT("Exorta os servos a que sejam submissos a seus senhores em tudo, sendo-lhes agradáveis, não os contradizendo");
    b->dados[TITO].capitulos[2].versos[10] = wxT("nem defraudando, antes mostrando perfeita lealdade, para que em tudo sejam ornamento da doutrina de Deus nosso Salvador.");
    b->dados[TITO].capitulos[2].versos[11] = wxT("Porque a graça de Deus se manifestou, trazendo salvação a todos os homens,");
    b->dados[TITO].capitulos[2].versos[12] = wxT("ensinando-nos, para que, renunciando à impiedade e às paixões mundanas, vivamos no presente mundo sóbria, e justa, e piamente,");
    b->dados[TITO].capitulos[2].versos[13] = wxT("aguardando a bem-aventurada esperança e o aparecimento da glória do nosso grande Deus e Salvador Cristo Jesus,");
    b->dados[TITO].capitulos[2].versos[14] = wxT("que se deu a si mesmo por nós para nos remir de toda a iniqüidade, e purificar para si um povo todo seu, zeloso de boas obras.");
    b->dados[TITO].capitulos[2].versos[15] = wxT("Fala estas coisas, exorta e repreende com toda autoridade. Ninguém te despreze.");

    b->dados[TITO].capitulos[3].versos[1] = wxT("Adverte-lhes que estejam sujeitos aos governadores e autoridades, que sejam obedientes, e estejam preparados para toda boa obra,");
    b->dados[TITO].capitulos[3].versos[2] = wxT("que a ninguém infamem, nem sejam contenciosos, mas moderados, mostrando toda a mansidão para com todos os homens.");
    b->dados[TITO].capitulos[3].versos[3] = wxT("Porque também nós éramos outrora insensatos, desobedientes, extraviados, servindo a várias paixões e deleites, vivendo em malícia e inveja odiosos e odiando-nos uns aos outros.");
    b->dados[TITO].capitulos[3].versos[4] = wxT("Mas quando apareceu a bondade de Deus, nosso Salvador e o seu amor para com os homens,");
    b->dados[TITO].capitulos[3].versos[5] = wxT("não em virtude de obras de justiça que nós houvéssemos feito, mas segundo a sua misericórdia, nos salvou mediante o lavar da regeneração e renovação pelo Espírito Santo,");
    b->dados[TITO].capitulos[3].versos[6] = wxT("que ele derramou abundantemente sobre nós por Jesus Cristo, nosso Salvador;");
    b->dados[TITO].capitulos[3].versos[7] = wxT("para que, sendo justificados pela sua graça, fôssemos feitos herdeiros segundo a esperança da vida eterna.");
    b->dados[TITO].capitulos[3].versos[8] = wxT("Fiel é esta palavra, e quero que a proclames com firmeza para que os que crêem em Deus procurem aplicar-se às boas obras. Essas coisas são boas e proveitosas aos homens.");
    b->dados[TITO].capitulos[3].versos[9] = wxT("Mas evita questões tolas, genealogias, contendas e debates acerca da lei; porque são coisas inúteis e vãs.");
    b->dados[TITO].capitulos[3].versos[10] = wxT("Ao homem faccioso, depois da primeira e segunda admoestação, evita-o,");
    b->dados[TITO].capitulos[3].versos[11] = wxT("sabendo que esse tal está pervertido, e vive pecando, e já por si mesmo está condenado.");
    b->dados[TITO].capitulos[3].versos[12] = wxT("Quando te enviar Ártemas, ou Tíquico, apressa-te a vir ter comigo a Nicópolis; porque tenho resolvido invernar ali.");
    b->dados[TITO].capitulos[3].versos[13] = wxT("Ajuda com empenho a Zenas, doutor da lei, e a Apolo, para que nada lhes falte na sua viagem.");
    b->dados[TITO].capitulos[3].versos[14] = wxT("Que os nossos também aprendam a aplicar-se às boas obras, para suprir as coisas necessárias, a fim de que não sejam infrutuosos.");
    b->dados[TITO].capitulos[3].versos[15] = wxT("Saúdam-te todos os que estão comigo. Saúda aqueles que nos amam na fé. A graça seja com todos vós.");

}
